const Component = () => {
  const [count, setCount] = useState(0);

  return (
    <div style={{
      padding: '30px',
      textAlign: 'center',
      border: '2px solid #0f62fe',
      borderRadius: '4px',
      backgroundColor: '#edf5ff'
    }}>
      <h2 style={{ margin: '0 0 20px 0', color: '#0043ce' }}>Counter Widget</h2>
      <div style={{
        fontSize: '48px',
        fontWeight: 'bold',
        color: '#0f62fe',
        margin: '20px 0'
      }}>
        {count}
      </div>
      <div style={{ display: 'flex', gap: '10px', justifyContent: 'center' }}>
        <button
          onClick={() => setCount(count - 1)}
          style={{
            padding: '10px 20px',
            fontSize: '16px',
            border: 'none',
            borderRadius: '0',
            backgroundColor: '#da1e28',
            color: 'white',
            cursor: 'pointer',
            fontWeight: '400'
          }}
        >
          -
        </button>
        <button
          onClick={() => setCount(0)}
          style={{
            padding: '10px 20px',
            fontSize: '16px',
            border: '1px solid #8d8d8d',
            borderRadius: '0',
            backgroundColor: 'white',
            color: '#161616',
            cursor: 'pointer'
          }}
        >
          Reset
        </button>
        <button
          onClick={() => setCount(count + 1)}
          style={{
            padding: '10px 20px',
            fontSize: '16px',
            border: 'none',
            borderRadius: '0',
            backgroundColor: '#24a148',
            color: 'white',
            cursor: 'pointer',
            fontWeight: '400'
          }}
        >
          +
        </button>
      </div>
    </div>
  );
};
